CREATE OR REPLACE FUNCTION fpa_gos_cmem_by_kep (p_code char , k_code char) RETURNS bigint AS $body$
DECLARE

    ldc_value integer;

BEGIN
    select count(sc_mem_m_membership_registered.membership_no) into STRICT ldc_value
    from sc_mem_m_membership_registered
        ,sc_mem_m_ucf_member_group
        ,sc_mem_m_ucf_province
    where (sc_mem_m_membership_registered.member_group_no = sc_mem_m_ucf_member_group.member_group_no)
    and (sc_mem_m_ucf_member_group.province_code = sc_mem_m_ucf_province.province_code)
    and (sc_mem_m_membership_registered.member_status_code = '0')
    and (sc_mem_m_ucf_province.province_code not in ('00'))
    and (trim(both sc_mem_m_ucf_province.province_code) = p_code)
    and (trim(both pka_mem_ctl.fp_kepmethod_memno(sc_mem_m_membership_registered.membership_no)) = k_code)
    group by sc_mem_m_ucf_province.province_code;
  return ldc_value;
 
exception when no_data_found then return 0;
when others then CALL spa_dberror('fpa_gos_cmem_by_kep');
end;
$body$
LANGUAGE PLPGSQL
SECURITY DEFINER
